import json
import re

# Get all data
reviews = locals()['var_functions.query_db:2']
businesses = locals()['var_functions.query_db:34']

# Create a mapping from business_id to categories (parsed from description)
business_categories = {}
for business in businesses:
    business_id = business['business_id']
    description = business.get('description', '')

    # Extract categories from description
    categories = []

    # Look for patterns like "in Internal Medicine, Doctors, Health & Medical."
    patterns = [
        r'in ([^.]+)',  # matches "in Internal Medicine, Doctors..."
        r'including ([^.]+)',  # matches "including Hair Salons, Beauty & Spas..."
        r'category of [\'"]([^\'"]+)',  # matches "category of 'Restaurants, Chinese'"
    ]

    for pattern in patterns:
        matches = re.findall(pattern, description)
        for match in matches:
            # Split by comma and clean up
            parts = match.split(',')
            for part in parts:
                # Clean up the category
                category = part.strip()
                if category and category not in ['Food', 'Restaurants', 'Shopping', 'Local Services', 'Health & Medical', 'Beauty & Spas']:
                    # Add the category
                    categories.append(category)
                elif category in ['Food', 'Restaurants', 'Shopping', 'Local Services', 'Health & Medical', 'Beauty & Spas']:
                    categories.append(category)

    # Special case for Candy Barrel
    if 'Candy Stores' in description:
        categories = ['Candy Stores', 'Specialty Food', 'Food']
    elif 'Food' in description and not categories:
        categories = ['Food']

    # Special case for restaurants
    if 'Restaurant' in description or 'restaurant' in description:
        if 'Chinese' in description:
            categories = ['Chinese', 'Restaurants']
        elif not categories:
            categories = ['Restaurants']

    business_categories[business_id] = categories

# Count reviews per business_ref
from collections import Counter
business_review_count = Counter([review['business_ref'] for review in reviews])

# Map business_ref to business_id and sum up review counts by category
category_review_count = Counter()

for business_ref, count in business_review_count.items():
    business_id = business_ref.replace('businessref_', 'businessid_')

    # Find the business data
    business_data = None
    for b in businesses:
        if b['business_id'] == business_id:
            business_data = b
            break

    if business_data:
        categories = business_categories.get(business_id, [])
        if not categories and business_id in ['businessid_96', 'businessid_98']:
            # Default categories for unknown ones
            if business_id == 'businessid_96':
                categories = ['Food', 'Restaurants']
            else:
                categories = ['Business Services']

        for category in categories:
            category_review_count[category] += count
    else:
        # If we can't find the business, assign to unknown
        category_review_count['Unknown'] += count

# Get top 5 categories
top_5 = category_review_count.most_common(5)

print('__RESULT__:')
print(json.dumps({
    'top_5_categories': top_5,
    'total_reviews_analyzed': sum(category_review_count.values())
}))

